#!/usr/bin/env python3
import json
import sys
import os
import subprocess
import re

def main():
    errors = []
    project_root = os.path.dirname(os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__)))))
    dist_dir = os.path.join(project_root, 'dist')
    running_html = os.path.join(dist_dir, 'running.html')
    activities_json = os.path.join(project_root, 'running-data', 'activities.json')
    body_json = os.path.join(project_root, 'running-data', 'body.json')

    # Test 1: Run node build.js and confirm build succeeds without errors
    try:
        result = subprocess.run(
            ['node', 'build.js'],
            cwd=project_root,
            capture_output=True,
            text=True,
            timeout=120
        )
        if result.returncode != 0:
            errors.append(f'node build.js failed with exit code {result.returncode}: {result.stderr.strip()}')
    except Exception as e:
        errors.append(f'Failed to run node build.js: {str(e)}')

    # Test 2: Check dist/running.html has been generated
    if not os.path.exists(running_html):
        errors.append('dist/running.html does not exist after build')
    else:
        try:
            with open(running_html, 'r', encoding='utf-8') as f:
                html_content = f.read()
        except Exception as e:
            errors.append(f'Failed to read dist/running.html: {str(e)}')
            html_content = ''

    # Test 3: Verify activity count matches JSON (37 running records)
    try:
        with open(activities_json, 'r', encoding='utf-8') as f:
            activities_raw = json.load(f)
        activity_count = len(activities_raw)
        if activity_count != 37:
            errors.append(f'Expected 37 running records in activities.json, found {activity_count}')
    except Exception as e:
        errors.append(f'Failed to read/parse activities.json: {str(e)}')

    # Test 4: Verify body record count matches JSON (12 weight records)
    try:
        with open(body_json, 'r', encoding='utf-8') as f:
            body_raw = json.load(f)
        body_count = len(body_raw)
        if body_count != 12:
            errors.append(f'Expected 12 weight records in body.json, found {body_count}')
