#!/usr/bin/env python3
import json
import sys
import os
import subprocess
import math

def main():
    errors = []
    project_root = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

    # --- Test 1: Run node build.js and confirm success ---
    try:
        result = subprocess.run(
            ['node', 'build.js'],
            cwd=project_root,
            capture_output=True,
            text=True,
            timeout=60
        )
        if result.returncode != 0:
            errors.append(f'node build.js failed with exit code {result.returncode}: {result.stderr.strip()}')
    except Exception as e:
        errors.append(f'Failed to run node build.js: {str(e)}')

    # --- Test 2: Check dist/running.html exists ---
    running_html_path = os.path.join(project_root, 'dist', 'running.html')
    if not os.path.exists(running_html_path):
        errors.append('dist/running.html does not exist')
    else:
        try:
            with open(running_html_path, 'r', encoding='utf-8') as f:
                html_content = f.read()
            if len(html_content.strip()) == 0:
                errors.append('dist/running.html is empty')
        except Exception as e:
            errors.append(f'Failed to read dist/running.html: {str(e)}')
            html_content = ''

    # --- Test 3: Verify data counts match JSON files ---
    activities_path = os.path.join(project_root, 'running-data', 'activities.json')
    body_path = os.path.join(project_root, 'running-data', 'body.json')

    activities = []
    body_data = []

    if os.path.exists(activities_path):
        try:
            with open(activities_path, 'r', encoding='utf-8') as f:
                activities = json.load(f)
        except Exception as e:
            errors.append(f'Failed to parse activities.json: {str(e)}')
    else:
        errors.append('running-data/activities.json does not exist')

    if os.path.exists(body_path):
        try:
            with open(body_path, 'r', encoding='utf-8') as f:
                body_data = json.load(f)
        except Exception as e:
            errors.append(f'Failed to parse body.json: {str(e)}')
    else:
        errors.append('running-data/body.json does not exist')

    # Verify 37 running records
    if len(activities) != 37:
        errors.append(f'Expected 37 activities in activities.json, found {len(activities)}')

    # Verify 12 body weight records
    if len(body_data) != 12:
        errors.append(f'Expected 12 body records in body.json, found {len(body_data)}')

    # Check that activity dates appear in running.html
    if html_content and activities:
        # Verify at least some activity dates are present in the HTML
        dates_found = 0
        for act in activities:
            if act['date'] in html_content:
                dates_found += 1
        if dates_found < len(activities):
            errors.append(
                f'Only {dates_found}/{len(activities)} activity dates found in running.html'
            )

    # Check that body data dates appear in running.html
    if html_content and body_data:
        body_dates_found = 0
        for bd in body_data:
            if bd['date'] in html_content:
                body_dates_found += 1
        if body_dates_found < len(body_data):
            errors.append(
                f'Only {body_dates_found}/{len(body_data)} body data dates found in running.html'
            )

    # Verify weight values appear in HTML
    if html_content and body_data:
        weights_found = 0
        for bd in body_data:
            weight_str = str(bd['weight_kg'])
            if weight_str in html_content:
                weights_found += 1
        if weights_found < len(body_data):
            errors.append(
                f'Only {weights_found}/{len(body_data)} body weight values found in running.html'
            )

    # --- Test 4: Verify pace format (e.g., 331 s/km -> "5'31\"") ---
    if html_content and activities:
        # Find the activity with avg_pace_s_per_km = 331 (date 2025-12-02)
        pace_331_activity = None
        for act in activities:
            if act.get('avg_pace_s_per_km') == 331:
                pace_331_activity = act
                break

        if pace_331_activity:
            expected_pace = "5'31\""
            if expected_pace not in html_content:
                errors.append(
                    f'Expected pace format "{expected_pace}" not found in running.html '
                    f'(for activity on {pace_331_activity["date"]} with avg_pace_s_per_km=331)'
                )
        else:
            # If 331 not found, verify pace format pattern exists for known activities
            # Use the first activity to compute expected pace
            first_act = activities[0]
            pace_s = first_act.get('avg_pace_s_per_km', 0)
            if pace_s > 0:
                mins = pace_s // 60
                secs = pace_s % 60
                expected_pace = f"{int(mins)}'{int(secs):02d}\""
                if expected_pace not in html_content:
                    errors.append(
                        f'Expected pace format "{expected_pace}" not found in running.html '
                        f'(for activity on {first_act["date"]} with avg_pace_s_per_km={pace_s})'
                    )

    # General pace format verification: check multiple activities
    if html_content and activities:
        pace_errors = 0
        for act in activities:
            pace_s = act.get('avg_pace_s_per_km', 0)
            if pace_s > 0:
                mins = int(pace_s // 60)
                secs = int(pace_s % 60)
                expected_pace = f"{mins}'{secs:02d}\""
                if expected_pace not in html_content:
                    pace_errors += 1
        if pace_errors > 0:
            errors.append(
                f'{pace_errors}/{len(activities)} activities have missing pace format in running.html'
            )

    # --- Test 5: Verify duration format (e.g., 2539 s -> "42min") ---
    if html_content and activities:
        # Find the activity with duration_s ~2539 (date 2025-11-11)
        duration_2539_activity = None
        for act in activities:
            if act.get('duration_s', 0) > 2500 and act.get('duration_s', 0) < 2600:
                duration_2539_activity = act
                break

        if duration_2539_activity:
            expected_duration = "42min"
            if expected_duration not in html_content:
                errors.append(
                    f'Expected duration format "{expected_duration}" not found in running.html '
                    f'(for activity on {duration_2539_activity["date"]} with duration_s={duration_2539_activity["duration_s"]:.1f})'
                )

    # General duration format verification: check multiple activities
    if html_content and activities:
        duration_errors = 0
        for act in activities:
            dur_s = act.get('duration_s', 0)
            if dur_s > 0:
                expected_min = math.floor(dur_s / 60)
                expected_duration = f"{expected_min}min"
                if expected_duration not in html_content:
                    duration_errors += 1
        if duration_errors > 0:
            errors.append(
                f'{duration_errors}/{len(activities)} activities have missing duration format in running.html'
            )

    # --- Build result ---
    result = {
        'pass': len(errors) == 0,
        'errors': errors
    }

    print(json.dumps(result))
    sys.exit(0 if result['pass'] else 1)

if __name__ == '__main__':
    main()

